import ast, subprocess, sys

def strip_docstrings(tree):
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef, ast.Module)):
            body = node.body
            if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], 'value', None), ast.Constant) and isinstance(body[0].value.value, str):
                node.body = body[1:]
                # keep body non-empty
                if not node.body:
                    node.body = [ast.Pass()]
    return tree

files = subprocess.check_output(
    ["git", "diff", "--name-only", "HEAD"], cwd="/home/polaris/wt/phase3ab2"
).decode().split()
files = [f for f in files if f.endswith(".py") and f.startswith("src/")]

failures = []
for f in files:
    head = subprocess.check_output(["git", "show", f"HEAD:{f}"], cwd="/home/polaris/wt/phase3ab2").decode()
    with open(f"/home/polaris/wt/phase3ab2/{f}") as fh:
        work = fh.read()
    try:
        h = ast.unparse(strip_docstrings(ast.parse(head)))
        w = ast.unparse(strip_docstrings(ast.parse(work)))
    except Exception as e:
        failures.append(f"{f}: PARSE ERROR {e}")
        continue
    if h != w:
        failures.append(f"{f}: AST DIFFERS after docstring strip")

print("FILES:", len(files))
if failures:
    print("FAIL")
    for x in failures:
        print(" ", x)
else:
    print("ALL PASS")

